const axios = require('axios');
const cheerio = require('cheerio');

try {
  const cookieHeader = $flow.state.cookieHeader;

  const url = "...";

  const postResponse = await axios.post(url, 
    "...",
    {
      headers: {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:147.0) Gecko/20100101 Firefox/147.0",
        "Content-Type": "application/x-www-form-urlencoded",
        "Cookie": cookieHeader,
        "Referer": "..."
      },
      validateStatus: function (status) {
        return status < 600;
      }
    }
  );

  const $ = cheerio.load(postResponse.data);
  let token = $('input[name="Token"]').val();

  if (!token) {
    const patterns = [
      /name=["']Token["']\s+value=["']([^"']+)["']/i,
      /value=["']([^"']+)["']\s+name=["']Token["']/i,
      /name="Token"[^>]*value="([^"]+)"/i,
      /value="([^"]+)"[^>]*name="Token"/i
    ];

    for (let pattern of patterns) {
      const match = postResponse.data.match(pattern);
      if (match && match[1]) {
        token = match[1];
        break;
      }
    }
  }

  if (!token) {
    return "Token nicht gefunden!";
  }

  $flow.state.token = token;

  return `Token erfolgreich extrahiert: ${token}`;

} catch (error) {
  return "FEHLER: " + error.message;
}

