inputs.customFunctionJavascriptFunction:
const axios = require("axios");

const USER_AGENT =
  "Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:147.0) Gecko/20100101 Firefox/147.0";

const POST_LOGIN_URL =
  "...";

const getCookieValue = (cookieHeader, key) => {
  if (!cookieHeader) return null;
  const match = cookieHeader.match(new RegExp(`(?:^|;\\s*)${key}=([^;]+)`));
  return match ? match[1] : null;
};

const removeEmptySessionCookies = (header = "") =>
  header
    .split(";")
    .map((c) => c.trim())
    .filter(Boolean)
    .filter((pair) => {
      if (!pair.startsWith("...")) return true;
      const [, ...rest] = pair.split("=");
      const value = rest.join("=");
      return value !== "";
    })
    .join("; ");

try {
  const loginCookies = $flow.state.cookieHeaderLogin;
  if (!loginCookies) return "FEHLER: cookieHeaderLogin fehlt.";

  const response = await axios.get(POST_LOGIN_URL, {
    headers: {
      "User-Agent": USER_AGENT,
      Cookie: loginCookies,
    },
    maxRedirects: 0,
    validateStatus: (s) => s >= 200 && s < 400,
  });

  const setCookie = response.headers["set-cookie"];
  if (!setCookie) return "Keine Cookies nach Login gefunden!";

  const cookieMap = (Array.isArray(setCookie) ? setCookie : [setCookie])
    .map((c) => c.split(";")[0].trim())
    .filter(Boolean)
    .reduce((acc, pair) => {
      const [key, ...rest] = pair.split("=");
      acc[key] = rest.join("=");
      return acc;
    }, {});

  if (!cookieMap...) {
    const FromLogin = getCookieValue(loginCookies, "...");
    if (FromLogin) cookieMap = FromLogin;
  }

  let cookieHeader = Object.entries(cookieMap)
    .map(([k, v]) => `${k}=${v}`)
    .join("; ");

  cookieHeader = removeEmptySessionCookies(cookieHeader);

  $flow.state.cookieHeader = cookieHeader;
  return cookieHeader;
} catch (error) {
  return "FEHLER: " + (error.response ? error.response.status : error.message);
}

