async function run() {
  try {
    const out = $flow.state.Output_Agent;
    if (out == null) return { success: false, error: "Output_Agent is empty" };

    let p = out;

    if (typeof p === "string") {
      let s = p.trim();

      if (s.startsWith("```")) {
        s = s.replace(/^```(?:json)?\s*/i, "").replace(/```$/i, "").trim();
      }

      p = JSON.parse(s);
    }

    const name = p?.name ?? null;
    const id = p?.id ?? null;
    const startDateTime = p?.startDateTime ?? null;
    const endDateTime = p?.endDateTime ?? null;

    $flow.state.Name = name;
    $flow.state.ID = id;
    $flow.state.StartDateTime = startDateTime;
    $flow.state.EndDateTime = endDateTime;

    const toUS = (iso) => {
      if (!iso) return { date: null, time: null };
      const d = new Date(iso);
      if (Number.isNaN(d.getTime())) return { date: null, time: null };

      const date = encodeURIComponent(
        `${String(d.getMonth() + 1).padStart(2, "0")}/${String(d.getDate()).padStart(2, "0")}/${d.getFullYear()}`
      );

      const h = d.getHours();
      const m = String(d.getMinutes()).padStart(2, "0");
      const h12 = h % 12 || 12;
      const ampm = h >= 12 ? "pm" : "am";
      const time = encodeURIComponent(`${h12}:${m} ${ampm}`).replace(/%20/g, "+");

      return { date, time };
    };

    const start = toUS(startDateTime);
    const end = toUS(endDateTime);

    $flow.state.StartDate_Day = start.date;
    $flow.state.StartDate_Time = start.time;
    $flow.state.EndDate_Day = end.date;
    $flow.state.EndDate_Time = end.time;

    return {
      success: true,
      name,
      id,
      startDateTime,
      endDateTime,
      StartDate_Day: start.date,
      StartDate_Time: start.time,
      EndDate_Day: end.date,
      EndDate_Time: end.time
    };
  } catch (e) {
    return { success: false, error: e?.message ?? String(e) };
  }
}

return await run();
